// Extract and validate evolution plan fields
const incoming = $input.first().json || {};
const body = incoming.body || {};
const headers = incoming.headers || {};

function getHeader(name) {
  const target = String(name).toLowerCase();
  for (const [key, value] of Object.entries(headers)) {
    if (String(key).toLowerCase() === target) {
      return Array.isArray(value) ? value[0] : value;
    }
  }
  return '';
}

const agent_id = body.agent_id;
const command_id = body.command_id || null;
const detected_gap = body.detected_gap;
const proposed_improvement = body.proposed_improvement;
const data_needed = body.data_needed || [];
const workflow_changes_needed = body.workflow_changes_needed || [];
const risk_level = body.risk_level || "medium";
const rollback_plan = body.rollback_plan || "";
const metadata = body.metadata || {};

const authHeader = String(getHeader('authorization') || '');
const bearerToken = authHeader.replace(/^Bearer\s+/i, '').trim();
const xAgentOSKey = String(getHeader('x-agentos-key') || '').trim();

const allowedRisks = ["low", "medium", "high"];
const riskValid = allowedRisks.includes(risk_level);

const expectedKey = process.env.S_AGENTOS_OPERATOR_KEY || process.env.S_AGENTOS_API_TOKEN || '';
const providedToken = xAgentOSKey || bearerToken;
const authValid = Boolean(expectedKey && providedToken && providedToken === expectedKey);
const requiredFieldsPresent = Boolean(agent_id && detected_gap && proposed_improvement);

return [{
  json: {
    agent_id, command_id, detected_gap, proposed_improvement, data_needed,
    workflow_changes_needed, risk_level: riskValid ? risk_level : "medium",
    rollback_plan, metadata,
    x_agentos_key: providedToken ? "[REDACTED]" : null,
    auth_method: xAgentOSKey ? "x-agentos-key" : (bearerToken ? "bearer" : "missing"),
    authValid, requiredFieldsPresent
  }
}];

const input = $input.first().json;

const plan = {
  agent_id: input.agent_id,
  command_id: input.command_id,
  detected_gap: input.detected_gap,
  proposed_improvement: input.proposed_improvement,
  data_needed: input.data_needed,
  workflow_changes_needed: input.workflow_changes_needed,
  risk_level: input.risk_level,
  rollback_plan: input.rollback_plan,
  approval_status: "pending",
  status: "draft",
  metadata: input.metadata
};

return [{ json: plan }];

const result = $input.first().json;
const plan_id = result.id || "unknown";
const agent_id = result.agent_id || "unknown";

return [{ json: {
  ok: true,
  route: "evolution_engine",
  plan_id: plan_id,
  agent_id: agent_id,
  approval_status: "pending",
  status: "draft",
  evolution_plan: {
    detected_gap: result.detected_gap,
    proposed_improvement: result.proposed_improvement,
    data_needed: result.data_needed || [],
    workflow_changes_needed: result.workflow_changes_needed || [],
    risk_level: result.risk_level,
    rollback_plan: result.rollback_plan,
    human_approval_required: true
  }
} }];
